// Validate required fields and normalise alert envelope
const body = $input.first().json.body ?? $input.first().json;

if (!body.tenant_id) {
  throw new Error('VALIDATION_FAIL: tenant_id is required');
}
if (!body.alert_details) {
  throw new Error('VALIDATION_FAIL: alert_details is required');
}

// Sanitise: strip any fields > 32 KB to prevent prompt stuffing
const alertStr = JSON.stringify(body.alert_details);
if (alertStr.length > 32768) {
  throw new Error('VALIDATION_FAIL: alert_details payload exceeds 32 KB limit');
}

return [{
  json: {
    tenant_id:     body.tenant_id,
    alert_details: body.alert_details,
    source_siem:   body.source_siem ?? 'Generic',
    received_at:   new Date().toISOString()
  }
}];

// Merge validated alert data with GitHub intel response
const alertData   = $('Validate & Normalise Input').first().json;
const githubNode  = $('Fetch GitHub Threat Intel').first();

// If GitHub fetch failed or returned empty, use fallback
const githubPayload = githubNode?.json?.data
  ?? githubNode?.json?.body
  ?? githubNode?.json
  ?? 'NO_INTEL_AVAILABLE';

const githubStr = typeof githubPayload === 'string'
  ? githubPayload
  : JSON.stringify(githubPayload);

return [{
  json: {
    tenant_id:           alertData.tenant_id,
    alert_details:       alertData.alert_details,
    source_siem:         alertData.source_siem,
    received_at:         alertData.received_at,
    github_raw_response: githubStr,
    intel_available:     githubStr !== 'NO_INTEL_AVAILABLE'
  }
}];

// Extract and validate the JSON verdict from Anthropic response
const response = $input.first().json;

// Anthropic returns content as array of blocks
let rawText = '';
if (response.content && Array.isArray(response.content)) {
  rawText = response.content
    .filter(b => b.type === 'text')
    .map(b => b.text)
    .join('');
} else if (typeof response === 'string') {
  rawText = response;
} else {
  rawText = JSON.stringify(response);
}

// Strip any accidental markdown fences
rawText = rawText.replace(/```json\n?/gi, '').replace(/```\n?/gi, '').trim();

let verdict;
try {
  verdict = JSON.parse(rawText);
} catch (e) {
  // Fallback: couldn't parse — route to manual investigation
  verdict = {
    tenant_id:              $('Merge Alert + Intel Context').first().json.tenant_id,
    analysis_summary:      'PARSE_ERROR: Agent output could not be parsed as JSON. Raw: ' + rawText.slice(0, 200),
    verdict:               'True Positive',
    confidence:             0.0,
    assigned_severity:     'High',
    mitre_tactics:         [],
    mitre_techniques:      [],
    ioc_extracted:         { ips: [], hashes: [], domains: [], processes: [], users: [], hostnames: [] },
    matched_github_rule:   null,
    playbook_matched:      false,
    containment_steps:     [],
    hitl_required:         true,
    automation_action_required: false,
    next_node_routing:     'Manual Investigation',
    escalate_to:           'HITL',
    evidence_tags:         ['parse_error', 'requires_review'],
    soc2_controls:         ['CC7.1', 'CC7.2'],
    analysis_timestamp:    new Date().toISOString()
  };
}

// Ensure analysis_timestamp is always present
if (!verdict.analysis_timestamp) {
  verdict.analysis_timestamp = new Date().toISOString();
}

return [{ json: verdict }];

// Emit structured audit log entry to $execution.customData
// In production, replace with your immutable audit ledger (Supabase append-only table)
const verdict = $input.first().json;
const alert   = $('Merge Alert + Intel Context').first().json;

const auditEntry = {
  event_id:           $execution.id + '-' + Date.now(),
  timestamp:          verdict.analysis_timestamp,
  tenant_id:          verdict.tenant_id,
  agent_id:           'vakros-soc-responder-v1',
  agent_version:      '1.0.0',
  action_type:        'triage',
  source_siem:        alert.source_siem,
  input_summary:      'Alert received at ' + alert.received_at + ' from ' + alert.source_siem,
  output_summary:     verdict.verdict + ' | ' + verdict.assigned_severity + ' | conf=' + verdict.confidence + ' | route=' + verdict.next_node_routing,
  framework_controls: (verdict.soc2_controls ?? []).map(c => 'SOC2:' + c),
  hitl_required:      verdict.hitl_required ?? false,
  human_approved_by:  null,
  confidence_score:   verdict.confidence,
  mitre_tactics:      verdict.mitre_tactics ?? [],
  mitre_techniques:   verdict.mitre_techniques ?? [],
  next_node_routing:  verdict.next_node_routing,
  escalate_to:        verdict.escalate_to
};

// Pass audit entry + original verdict downstream
return [{ json: { ...verdict, _audit: auditEntry } }];

// HIGH RISK — requires human approval before execution
// In production: send approval request to Slack / PagerDuty / email
// Execution is BLOCKED until human approves
const v = $input.first().json;

const hitlRequest = {
  type:           'HITL_APPROVAL_REQUIRED',
  priority:       'CRITICAL',
  tenant_id:      v.tenant_id,
  requested_action: 'Isolate Host',
  reason:         v.analysis_summary,
  severity:       v.assigned_severity,
  confidence:     v.confidence,
  mitre_tactics:  v.mitre_tactics,
  containment_steps: v.containment_steps,
  ioc_extracted:  v.ioc_extracted,
  soc2_controls:  v.soc2_controls,
  decision_deadline: new Date(Date.now() + 15 * 60 * 1000).toISOString(), // 15 min SLA
  audit_ref:      v._audit?.event_id
};

// TODO: Wire to your Slack/PagerDuty notification node here
// For now, log and halt
console.log('HITL_REQUEST', JSON.stringify(hitlRequest));

return [{ json: { status: 'HITL_PENDING', hitl_request: hitlRequest, original_verdict: v } }];

// Tier-2 Autonomous — block IPs without HITL
// In production: replace with HTTP Request to your firewall/EDR API
const v = $input.first().json;

const ipsToBlock = v.ioc_extracted?.ips ?? [];

if (ipsToBlock.length === 0) {
  return [{ json: {
    status: 'BLOCK_IP_NO_IPS',
    message: 'No IPs extracted from alert — routing to SOC2 for manual review',
    tenant_id: v.tenant_id,
    verdict: v
  }}];
}

// Build the containment command payload
const containmentPayload = {
  action:     'block_ip',
  tenant_id:  v.tenant_id,
  ips:        ipsToBlock,
  reason:     v.analysis_summary,
  severity:   v.assigned_severity,
  confidence: v.confidence,
  mitre:      v.mitre_techniques,
  soc2_controls: v.soc2_controls,
  executed_at:   new Date().toISOString(),
  audit_ref:     v._audit?.event_id
};

// TODO: Send containmentPayload to firewall/EDR HTTP Request node
console.log('BLOCK_IP_EXEC', JSON.stringify(containmentPayload));

return [{ json: { status: 'BLOCK_IP_QUEUED', payload: containmentPayload } }];

// Escalate to SOC2 — create investigation case
// In production: replace with HTTP Request to your case management system (Jira/Linear/ServiceNow)
const v = $input.first().json;

const ticket = {
  type:           'SOC2_INVESTIGATION',
  tenant_id:      v.tenant_id,
  title:          `[${v.assigned_severity}] ${v.verdict} — ${(v.mitre_tactics ?? []).join(', ') || 'Unknown TTP'}`,
  description:    v.analysis_summary,
  severity:       v.assigned_severity,
  confidence:     v.confidence,
  verdict:        v.verdict,
  mitre_tactics:  v.mitre_tactics,
  mitre_techniques: v.mitre_techniques,
  ioc_extracted:  v.ioc_extracted,
  containment_steps: v.containment_steps,
  playbook_matched:  v.playbook_matched,
  matched_github_rule: v.matched_github_rule,
  soc2_controls:  v.soc2_controls,
  created_at:     new Date().toISOString(),
  audit_ref:      v._audit?.event_id,
  escalate_to:    'SOC2'
};

// TODO: Wire to Jira/Linear/ServiceNow HTTP Request node
console.log('SOC2_TICKET', JSON.stringify(ticket));

return [{ json: { status: 'SOC2_TICKET_CREATED', ticket } }];

// False Positive — high confidence benign, close and log
const v = $input.first().json;

const closure = {
  type:          'CASE_CLOSED_BENIGN',
  tenant_id:     v.tenant_id,
  verdict:       v.verdict,
  confidence:    v.confidence,
  reason:        v.analysis_summary,
  evidence_tags: v.evidence_tags,
  soc2_controls: v.soc2_controls,
  closed_at:     new Date().toISOString(),
  audit_ref:     v._audit?.event_id
};

console.log('CASE_CLOSED', JSON.stringify(closure));

return [{ json: { status: 'CLOSED_BENIGN', closure } }];

// Low confidence or no GitHub match — escalate to human analyst
const v = $input.first().json;

const escalation = {
  type:            'MANUAL_INVESTIGATION_REQUIRED',
  priority:        v.assigned_severity === 'Critical' || v.assigned_severity === 'High' ? 'HIGH' : 'MEDIUM',
  tenant_id:       v.tenant_id,
  reason:          v.confidence < 0.60
                     ? `Low confidence (${v.confidence}) — insufficient data for autonomous decision`
                     : v.intel_available === false
                     ? 'No GitHub threat intel available'
                     : 'No matching playbook — manual analysis required',
  verdict:         v.verdict,
  confidence:      v.confidence,
  severity:        v.assigned_severity,
  analysis_summary: v.analysis_summary,
  ioc_extracted:   v.ioc_extracted,
  mitre_tactics:   v.mitre_tactics,
  soc2_controls:   v.soc2_controls,
  escalate_to:     v.escalate_to ?? 'HITL',
  created_at:      new Date().toISOString(),
  audit_ref:       v._audit?.event_id
};

// TODO: Wire to notification node (Slack/email/PagerDuty)
console.log('MANUAL_ESCALATION', JSON.stringify(escalation));

return [{ json: { status: 'ESCALATED_MANUAL', escalation } }];
